import type { FogMemory, TileGrid } from "../map/index.js";
import type { EntityId, GameState } from "../state/index.js";

export type FloorKnowledge = {
  readonly mapRevealed?: boolean;
  readonly revealedItemIds?: readonly EntityId[];
  readonly revealedEnemyIds?: readonly EntityId[];
  readonly revealedTrapIds?: readonly EntityId[];
};

type FloorRuntimeOpaque = TileGrid & {
  readonly fog?: FogMemory;
  readonly knowledge?: FloorKnowledge;
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (
    opaque === null ||
    typeof opaque !== "object" ||
    !("kind" in opaque) ||
    opaque.kind !== "tile-grid" ||
    typeof opaque.width !== "number" ||
    typeof opaque.height !== "number" ||
    !Array.isArray(opaque.tiles)
  ) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

export const fogFromState = (
  state: GameState,
  grid: TileGrid,
): FogMemory | null => {
  const fog = (state.floor.geometry.opaque as FloorRuntimeOpaque | null)?.fog;

  if (
    fog !== undefined &&
    fog.width === grid.width &&
    fog.height === grid.height &&
    fog.tiles.length === grid.tiles.length
  ) {
    return fog;
  }

  return null;
};

export const defaultVisibleFog = (grid: TileGrid): FogMemory => ({
  ownerId: "player",
  width: grid.width,
  height: grid.height,
  tiles: grid.tiles.map((tile) => ({
    state: "visible" as const,
    rememberedTile: tile,
  })),
});

export const floorKnowledge = (state: GameState): FloorKnowledge =>
  (state.floor.geometry.opaque as FloorRuntimeOpaque | null)?.knowledge ?? {};

export const isTrapRevealed = (
  state: GameState,
  trapId: EntityId,
  behaviorRuntime: { readonly [key: string]: unknown },
): boolean => {
  if (behaviorRuntime.revealed === true) {
    return true;
  }

  const knowledge = floorKnowledge(state);

  return knowledge.revealedTrapIds?.includes(trapId) ?? false;
};

import type { ItemDefinition } from "../../schemas/entities/index.js";
import type { Tile } from "../map/index.js";
import { Terrain } from "../map/index.js";

export const GLYPH_PLAYER = "@";

export const GLYPH_TRAP = "^";

export const GLYPH_NPC = "N";

export const GLYPH_ENEMY_FALLBACK = "e";

export const terrainGlyph = (tile: Tile): string => {
  switch (tile.terrain) {
    case Terrain.Wall:
      return "#";
    case Terrain.Floor:
      return ".";
    case Terrain.Door:
      return tile.door === "open" ? "'" : "+";
    case Terrain.Water:
      return "~";
    case Terrain.StairsDown:
      return ">";
    case Terrain.Entrance:
      return "<";
  }
};

export const rememberedTerrainGlyph = (tile: Tile): string => {
  switch (tile.terrain) {
    case Terrain.Wall:
      return ":";
    case Terrain.Floor:
      return ",";
    case Terrain.Door:
      return tile.door === "open" ? "'" : "+";
    case Terrain.Water:
      return ",";
    case Terrain.StairsDown:
      return ">";
    case Terrain.Entrance:
      return "<";
  }
};

export const itemGlyph = (
  definition: ItemDefinition,
  identified: boolean,
): string => {
  if (!identified) {
    return "?";
  }

  switch (definition.kind) {
    case "draught":
      return "!";
    case "weapon":
    case "armor":
    case "charm":
      return "=";
    case "food":
      return "%";
    case "coin":
      return "$";
    case "note":
      return '"';
    case "throwable":
      return ")";
    case "tool":
      return "(";
    case "key_item":
      return "-";
    default:
      return definition.glyph.slice(0, 1);
  }
};

export const enemyGlyph = (glyph: string | undefined): string =>
  glyph === undefined || glyph.length === 0 ? GLYPH_ENEMY_FALLBACK : glyph.slice(0, 1);

export { render, renderHudLine } from "./grid.js";
export {
  ALL_LOG_EVENT_TYPES,
  dummyLogEvent,
  formatLogEvent,
} from "./log.js";

import {
  validDraughtItemFixture,
  validEnemyDefinitionFixture,
  validTrapDefinitionFixture,
} from "../../schemas/fixtures/entities.js";
import {
  createTile,
  createTileGrid,
  idx,
  updateFogMemory,
  visibleCells,
  withTile,
  Terrain,
  type Tile,
  type TileGrid,
} from "../map/index.js";
import { createInitialState } from "../state/index.js";
import type {
  EnemyEntityInstance,
  EntityId,
  GameState,
  GroundItemEntityInstance,
  Position,
  TrapEntityInstance,
} from "../state/index.js";
import type { FogMemory } from "../map/index.js";

export const midActionFixtureState = (): GameState => {
  const grid = createTileGrid({
    width: 5,
    height: 3,
    tiles: parseAsciiTiles([
      "#####",
      "#@.e#",
      "#+>?#",
    ]),
  });

  const playerPosition = { x: 1, y: 1 };
  const state = withFloorGrid(
    withPlayer(
      createInitialState("render-mid-action"),
      {
        position: playerPosition,
        hp: { current: 14, max: 20 },
        level: 2,
        xp: 35,
        fullness: { current: 72, max: 100 },
        statuses: [{ status: "poison", duration: 2 }],
        turn: 7,
        depth: 2,
      },
    ),
    grid,
    createFogMemoryForGrid(grid),
  );

  return {
    ...state,
    entities: {
      "enemy#1": enemyAt("enemy#1", { x: 3, y: 1 }),
      "item#1": itemAt("item#1", validDraughtItemFixture, { x: 2, y: 1 }, false),
      "trap#1": trapAt("trap#1", { x: 3, y: 2 }, true),
    },
    ids: {
      entityCounters: {
        enemy: 1,
        item: 1,
        npc: 0,
        trap: 1,
      },
    },
  };
};

export const fogMixFixtureState = (): GameState => {
  const grid = createTileGrid({
    width: 5,
    height: 3,
    tiles: parseAsciiTiles([
      "#####",
      "#@.##",
      "#...#",
    ]),
  });
  const origin = { x: 1, y: 1 };
  const wall = { x: 3, y: 1 };
  const initialFog = createFogMemoryForGrid(grid);
  const visibleFog = updateFogMemory(
    initialFog,
    grid,
    visibleCells(grid, origin, 2),
  );
  const changedGrid = withTile(grid, wall, createTile(Terrain.Floor));
  const rememberedFog = updateFogMemory(
    visibleFog,
    changedGrid,
    new Set([idx(grid, origin)]),
  );

  return withFloorGrid(
    withPlayer(createInitialState("render-fog-mix"), {
      position: origin,
      turn: 4,
    }),
    changedGrid,
    rememberedFog,
  );
};

const parseAsciiTiles = (rows: readonly string[]): Tile[] => {
  const tiles: Tile[] = [];

  for (const row of rows) {
    for (const character of row) {
      tiles.push(tileForCharacter(character));
    }
  }

  return tiles;
};

const tileForCharacter = (character: string): Tile => {
  switch (character) {
    case "#":
      return createTile(Terrain.Wall);
    case ".":
    case "@":
    case "e":
      return createTile(Terrain.Floor);
    case "+":
      return createTile(Terrain.Door, "closed");
    case ">":
      return createTile(Terrain.StairsDown);
    case "?":
      return createTile(Terrain.Water);
    default:
      throw new Error(`unsupported fixture character ${character}`);
  }
};

const createFogMemoryForGrid = (grid: TileGrid): FogMemory => ({
  ownerId: "player",
  width: grid.width,
  height: grid.height,
  tiles: grid.tiles.map(() => ({
    state: "visible" as const,
    rememberedTile: null,
  })),
});

type PlayerOverrides = {
  readonly position?: Position;
  readonly hp?: { readonly current: number; readonly max: number };
  readonly level?: number;
  readonly xp?: number;
  readonly fullness?: { readonly current: number; readonly max: number };
  readonly statuses?: GameState["player"]["statuses"];
  readonly turn?: number;
  readonly depth?: number;
};

const withPlayer = (
  state: GameState,
  overrides: PlayerOverrides,
): GameState => ({
  ...state,
  run: {
    ...state.run,
    turn: overrides.turn ?? state.run.turn,
    depth: overrides.depth ?? state.run.depth,
  },
  floor: {
    ...state.floor,
    depth: overrides.depth ?? state.floor.depth,
  },
  player: {
    ...state.player,
    position: overrides.position ?? state.player.position,
    hp: overrides.hp ?? state.player.hp,
    level: overrides.level ?? state.player.level,
    xp: overrides.xp ?? state.player.xp,
    fullness: overrides.fullness ?? state.player.fullness,
    statuses: overrides.statuses ?? state.player.statuses,
  },
});

const withFloorGrid = (
  state: GameState,
  grid: TileGrid,
  fog: FogMemory,
): GameState => ({
  ...state,
  floor: {
    ...state.floor,
    geometry: {
      refId: state.floor.geometry.refId,
      opaque: {
        ...grid,
        fog,
      },
    },
  },
});

const enemyAt = (id: EntityId, position: Position): EnemyEntityInstance => ({
  id,
  kind: "enemy",
  definition:
    validEnemyDefinitionFixture as unknown as EnemyEntityInstance["definition"],
  position,
  currentHP: 6,
  statuses: [],
  behaviorRuntime: {},
});

const itemAt = (
  id: EntityId,
  definition: GroundItemEntityInstance["definition"],
  position: Position,
  identified: boolean,
): GroundItemEntityInstance => ({
  id,
  kind: "item",
  definition,
  position,
  currentHP: null,
  quantity: 1,
  identified,
  statuses: [],
  behaviorRuntime: {},
});

const trapAt = (
  id: EntityId,
  position: Position,
  revealed: boolean,
): TrapEntityInstance => ({
  id,
  kind: "trap",
  definition: validTrapDefinitionFixture,
  position,
  currentHP: null,
  armed: true,
  statuses: [],
  behaviorRuntime: revealed ? { revealed: true } : {},
});

import type { GameConfig } from "../../config/index.js";
import type {
  DepthBand,
  EnemyDefinition,
  ItemDefinition,
  NpcDefinition,
  QuestDefinition,
  TrapDefinition,
} from "../../schemas/entities/index.js";
import type {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import type { StatusApplication } from "../../schemas/vocab/index.js";

export type SerializablePrimitive = string | number | boolean | null;

export type SerializableValue =
  | SerializablePrimitive
  | readonly SerializableValue[]
  | { readonly [key: string]: SerializableValue };

export type SerializableRecord = {
  readonly [key: string]: SerializableValue;
};

export const ACTIVE_TERMINAL_STATUS = "ACTIVE" as const;

export type ConfiguredTerminalStatus =
  GameConfig["runStructure"]["terminalStates"][keyof GameConfig["runStructure"]["terminalStates"]];

export type TerminalStatus =
  | typeof ACTIVE_TERMINAL_STATUS
  | ConfiguredTerminalStatus;

export interface VersionStamp {
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: typeof ENGINE_VERSION;
}

export interface RunMeta {
  readonly runId: string;
  readonly seed: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly turn: number;
  readonly terminalStatus: TerminalStatus;
  readonly itemKnowledge: ItemKnowledgeState;
}

export interface ItemKnowledgeState {
  readonly identifiedDefinitionIds: readonly string[];
  readonly bonusRevealedItemInstanceIds: readonly string[];
  readonly chargesByItemInstanceId: {
    readonly [itemInstanceId: string]: number;
  };
}

export interface Position {
  readonly x: number;
  readonly y: number;
}

export interface FloorGeometrySlot {
  readonly refId: string;
  /*
   * PHASE-07A contract: the map module owns this payload's concrete shape.
   * PHASE-06 only requires a stable, serializable geometry reference by id.
   */
  readonly opaque: SerializableRecord | null;
}

export interface FloorState {
  readonly floorId: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly geometry: FloorGeometrySlot;
}

export interface PlayerItemStack {
  readonly itemInstanceId: string;
  readonly definition: ItemDefinition;
  readonly quantity: number;
  readonly identified: boolean;
}

export type InventorySlot = PlayerItemStack | null;

export interface EquipmentState {
  readonly weapon: PlayerItemStack | null;
  readonly armor: PlayerItemStack | null;
  readonly charms: readonly (PlayerItemStack | null)[];
}

export interface PlayerState {
  readonly hp: {
    readonly current: number;
    readonly max: number;
  };
  readonly level: number;
  readonly xp: number;
  readonly fullness: {
    readonly current: number;
    readonly max: number;
  };
  readonly position: Position;
  readonly inventory: readonly InventorySlot[];
  readonly equipment: EquipmentState;
  readonly statuses: readonly StatusApplication[];
}

export type EntityKind = "enemy" | "npc" | "item" | "trap";

export type EntityIdCounters = {
  readonly [Kind in EntityKind]: number;
};

export type EntityId = `${EntityKind}#${number}`;

export interface EntityRuntimeFields {
  readonly id: EntityId;
  readonly position: Position;
  readonly currentHP: number | null;
  readonly statuses: readonly StatusApplication[];
  readonly behaviorRuntime: SerializableRecord;
}

export interface EnemyEntityInstance extends EntityRuntimeFields {
  readonly kind: "enemy";
  readonly definition: EnemyDefinition;
  readonly currentHP: number;
}

export interface NpcEntityInstance extends EntityRuntimeFields {
  readonly kind: "npc";
  readonly definition: NpcDefinition;
  readonly dialogueRuntime: SerializableRecord;
}

export interface GroundItemEntityInstance extends EntityRuntimeFields {
  readonly kind: "item";
  readonly definition: ItemDefinition;
  readonly currentHP: null;
  readonly quantity: number;
  readonly identified: boolean;
}

export interface TrapEntityInstance extends EntityRuntimeFields {
  readonly kind: "trap";
  readonly definition: TrapDefinition;
  readonly currentHP: null;
  readonly armed: boolean;
}

export type EntityInstance =
  | EnemyEntityInstance
  | NpcEntityInstance
  | GroundItemEntityInstance
  | TrapEntityInstance;

export type EntityMap = {
  readonly [id: string]: EntityInstance;
};

export type QuestRuntimeStatus = "available" | "active" | "completed" | "failed";

export interface QuestRuntime {
  readonly definition: QuestDefinition;
  readonly status: QuestRuntimeStatus;
  readonly progress: SerializableRecord;
}

export interface QuestState {
  readonly quests: {
    readonly [id: string]: QuestRuntime;
  };
  readonly activeQuestIds: readonly string[];
  readonly completedQuestIds: readonly string[];
  readonly failedQuestIds: readonly string[];
}

/*
 * Log extension pattern:
 * later engine systems add event types by declaration-merging this interface.
 * The runtime serializer validates the event envelope and serializable data.
 */
export interface EngineLogEventDataByType {
  readonly state_created: {
    readonly runId: string;
    readonly seed: string;
    readonly depth: number;
    readonly band: DepthBand;
  };
  readonly state_serialized: {
    readonly format: "stable-json";
  };
  readonly state_deserialized: {
    readonly format: "stable-json";
  };
}

export type EngineLogEventType = Extract<
  keyof EngineLogEventDataByType,
  string
>;

export type EngineLogEvent = {
  readonly [Type in EngineLogEventType]: {
    readonly turn: number;
    readonly type: Type;
    readonly data: EngineLogEventDataByType[Type];
  };
}[EngineLogEventType];

export interface RngStreamCursor {
  readonly streamId: string;
  readonly seed: string;
  readonly parentStreamId: string | null;
  readonly draws: number;
}

export interface RngState {
  readonly rootSeed: string;
  readonly streams: {
    readonly [streamId: string]: RngStreamCursor;
  };
}

export interface IdState {
  readonly entityCounters: EntityIdCounters;
}

export interface GameState {
  readonly version: VersionStamp;
  readonly run: RunMeta;
  readonly floor: FloorState;
  readonly player: PlayerState;
  readonly entities: EntityMap;
  readonly quests: QuestState;
  readonly log: readonly EngineLogEvent[];
  readonly rng: RngState;
  readonly ids: IdState;
}

